               >
                   LOAD CHECKPOINT
               </button>
             )}

             <button 
               onClick={resetGame}
               className="w-full py-4 bg-red-700 hover:bg-red-600 text-white font-bold tracking-widest transition-all rounded-sm shadow-[0_0_20px_rgba(185,28,28,0.4)]"
