import React, { useEffect, useState } from 'react';
import { GameProvider, useGame } from './context/GameContext';
import { MonetizationProvider, useMonetization } from './context/MonetizationContext';
import { SplashScreen } from './components/SplashScreen';
import { StoryView } from './components/StoryView';
import { ThemeSelector } from './components/ThemeSelector';
import { Paywall } from './components/Paywall';
import { AdOverlay } from './components/AdOverlay';
import { GameOverScreen } from './components/GameOverScreen'; // Import new component
import { AppStatus } from './types';

const GameContent: React.FC = () => {
  const { appStatus, enterThemeSelection, resetGame, isLoading, saveGame, loadGame, hasSave } = useGame();
  const { isAdShowing, isPremium, showPaywallModal, openPaywall, closePaywall } = useMonetization();
  const [showSplash, setShowSplash] = useState(true);
  const [saveNotification, setSaveNotification] = useState(false);

  // Handle Splash Screen Logic
  useEffect(() => {
    const timer = setTimeout(() => {
      setShowSplash(false);
    }, 2500); // 2.5s splash
    return () => clearTimeout(timer);
  }, []);

  const handleSave = () => {
    saveGame();
    setSaveNotification(true);
    setTimeout(() => setSaveNotification(false), 2000);
  };

  if (showSplash) {
    return <SplashScreen />;
  }

  // GAME OVER STATE
  if (appStatus === AppStatus.GAME_OVER) {
    return (
      <div className="w-full h-screen bg-black relative">
        <GameOverScreen />
        {isAdShowing && <AdOverlay />}
      </div>
    );
  }

  // THEME SELECTION STATE
  if (appStatus === AppStatus.THEME_SELECT) {
    return (
      <div className="w-full h-screen bg-black">
        <ThemeSelector />
        {isAdShowing && <AdOverlay />}
      </div>
    );
  }

  // MENU STATE
  if (appStatus === AppStatus.MENU || appStatus === AppStatus.SPLASH) {
     return (
       <div className="relative w-full h-screen bg-black flex flex-col items-center justify-center overflow-hidden">
         {/* Abstract BG */}
         <div className="absolute inset-0 bg-[url('https://picsum.photos/1920/1080?grayscale&blur=8')] bg-cover opacity-30" />

         <div className="z-10 text-center space-y-8 p-4">
           <h1 className="text-6xl md:text-8xl font-bold cinematic-text text-white tracking-tighter mb-4">CHRONOS</h1>
           <p className="text-xl text-gray-400 max-w-md mx-auto">Infinite possibilities. One timeline. Yours.</p>

           <div className="flex flex-col gap-4 w-full max-w-xs mx-auto">
             {hasSave && (
               <button 
                 onClick={loadGame}
                 disabled={isLoading}
                 className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold tracking-widest transition-all rounded-sm flex justify-center items-center gap-2 border border-indigo-400/50 shadow-[0_0_15px_rgba(79,70,229,0.5)]"
               >
                   CONTINUE TIMELINE
               </button>
             )}

             <button 
               onClick={enterThemeSelection}
               disabled={isLoading}
               className={`w-full py-4 bg-white text-black font-bold tracking-widest transition-all rounded-sm flex justify-center items-center gap-2 ${isLoading ? 'opacity-70 cursor-not-allowed' : 'hover:bg-gray-200'}`}
             >
                 {hasSave ? 'NEW TIMELINE' : 'BEGIN STORY'}
             </button>

             {!isPremium && (
                <button 
                  onClick={openPaywall}
                  disabled={isLoading}
                  className="w-full py-4 border border-white/20 text-white hover:bg-white/10 transition-colors rounded-sm text-sm tracking-widest disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  REMOVE ADS
                </button>
             )}
           </div>
         </div>

         {showPaywallModal && <Paywall onClose={closePaywall} />}
       </div>
     );
  }

  // PLAYING STATE
  return (
    <div className="w-full h-screen bg-black relative">
      <StoryView />

      {/* Controls Top Right */}
      <div className="fixed top-4 right-4 z-40 flex items-center gap-3">
        {/* Save Notification */}
        <div className={`transition-all duration-500 ${saveNotification ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-4'} pointer-events-none`}>
          <span className="text-[10px] uppercase tracking-widest text-emerald-400 bg-black/50 backdrop-blur px-3 py-1 rounded-full border border-emerald-500/30">
            Checkpoint Saved
          </span>
        </div>

        <button 
          onClick={handleSave}
          disabled={isLoading}
          className="w-10 h-10 flex items-center justify-center rounded-full bg-black/50 hover:bg-black/80 text-white border border-white/20 transition-all hover:scale-110 active:scale-95 disabled:opacity-50"
          title="Save Progress"
        >
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
            <path strokeLinecap="round" strokeLinejoin="round" d="M16.5 3.75V16.5L12 14.25 7.5 16.5V3.75m9 0H18A2.25 2.25 0 0 1 20.25 6v12A2.25 2.25 0 0 1 18 20.25H6A2.25 2.25 0 0 1 3.75 18V6A2.25 2.25 0 0 1 6 3.75h1.5m9 0h-9" />
          </svg>
        </button>

        <button 
          onClick={resetGame}
          className="w-10 h-10 flex items-center justify-center rounded-full bg-black/50 hover:bg-red-900/50 text-white border border-white/20 transition-transform hover:rotate-90 hover:border-red-500/50"
          title="Exit to Menu"
        >
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-4 h-4">
            <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      {/* Global Overlays */}
      {isAdShowing && <AdOverlay />}
      {showPaywallModal && <Paywall onClose={closePaywall} />}
    </div>
  );
};

const App: React.FC = () => {
  return (
    <MonetizationProvider>
      <GameProvider>
        <GameContent />
      </GameProvider>
    </MonetizationProvider>
  );
};

export default App;

import React from 'react';
import { useGame } from '../context/GameContext';
import { StoryTheme } from '../types';

const themes: { id: StoryTheme; title: string; desc: string }[] = [
