        >
             {/* Loading State for Bottom Area (if needed, otherwise hidden by translate) */}
             {isLoading && (
                 <div className="absolute bottom-0 w-full p-6 text-center">
                    <span className="text-xs tracking-[0.3em] uppercase text-indigo-300/80 animate-pulse">Simulating...</span>
                 </div>
