             {/* Drawer Content */}
            <div className={`w-full bg-gray-950/95 backdrop-blur-xl border-t border-white/10 shadow-[0_-10px_40px_rgba(0,0,0,0.8)] transition-all duration-500 ease-in-out flex flex-col ${isDrawerOpen ? 'max-h-[80vh]' : 'max-h-24'}`}>

                {/* Toggle Handle / Header */}
                <button 
                    onClick={() => setIsDrawerOpen(!isDrawerOpen)}
