                            className={`w-4 h-4 text-indigo-400 transition-transform duration-500 ${isDrawerOpen ? 'rotate-180' : ''}`}
                        >
                            <path strokeLinecap="round" strokeLinejoin="round" d="M4.5 15.75l7.5-7.5 7.5 7.5" />
                        </svg>
                    </div>
                </button>

                {/* Options List */}
                <div className={`overflow-y-auto px-6 pb-12 transition-all duration-300 ${isDrawerOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none h-0'}`}>
